 1	import type { FC } from 'react';
 2	import { useForkliftTranslation } from 'src/utils/i18n';
 3	
 4	import {
 5	  NetworkMapModelGroupVersionKind,
 6	  StorageMapModelGroupVersionKind,
 7	  type V1beta1Plan,
 8	} from '@kubev2v/types';
 9	import { ResourceLink } from '@openshift-console/dynamic-plugin-sdk';
10	import {
11	  DescriptionList,
12	  DescriptionListDescription,
13	  DescriptionListGroup,
14	  DescriptionListTerm,
15	  Split,
16	  SplitItem,
17	} from '@patternfly/react-core';
18	import {
19	  getPlanNetworkMapName,
20	  getPlanNetworkMapNamespace,
21	  getPlanStorageMapName,
22	  getPlanStorageMapNamespace,
23	} from '@utils/crds/plans/selectors';
24	
25	import type { Mapping } from '../utils/types';
26	
27	import MappingList from './MappingList';
28	
29	type PlanMappingsViewModeProps = {
30	  plan: V1beta1Plan;
31	  labeledNetworkMappings: Mapping[];
32	  labeledStorageMappings: Mapping[];
33	};
34	const PlanMappingsViewMode: FC<PlanMappingsViewModeProps> = ({
35	  labeledNetworkMappings,
36	  labeledStorageMappings,
37	  plan,
38	}) => {
39	  const { t } = useForkliftTranslation();
40	
41	  return (
42	    <>
43	      <DescriptionList columnModifier={{ default: '1Col' }}>
44	        <DescriptionListGroup data-testid="network-mappings-section">
45	          <DescriptionListTerm>
46	            <Split hasGutter>
47	              <SplitItem>{t('Network map:')}</SplitItem>
48	              <SplitItem>
49	                <ResourceLink
50	                  groupVersionKind={NetworkMapModelGroupVersionKind}
51	                  name={getPlanNetworkMapName(plan)}
52	                  namespace={getPlanNetworkMapNamespace(plan)}
53	                  inline
54	                />
55	              </SplitItem>
56	            </Split>
57	          </DescriptionListTerm>
58	          <DescriptionListDescription>
59	            <MappingList
60	              mappings={labeledNetworkMappings}
61	              generalSourcesLabel={t('Other networks present on the source provider ')}
62	              noSourcesLabel={t('No networks in this category')}
63	              isEditable={false}
64	              testId="network-mappings-list"
65	            />
66	          </DescriptionListDescription>
67	        </DescriptionListGroup>
68	        <DescriptionListGroup data-testid="storage-mappings-section">
69	          <DescriptionListTerm>
70	            <Split hasGutter>
71	              <SplitItem>{t('Storage map:')}</SplitItem>
72	              <SplitItem>
73	                <ResourceLink
74	                  groupVersionKind={StorageMapModelGroupVersionKind}
75	                  name={getPlanStorageMapName(plan)}
76	                  namespace={getPlanStorageMapNamespace(plan)}
77	                  inline
78	                />
79	              </SplitItem>
80	            </Split>
81	          </DescriptionListTerm>
82	          <DescriptionListDescription>
83	            <MappingList
84	              mappings={labeledStorageMappings}
85	              generalSourcesLabel={t('Other storages present on the source provider ')}
86	              noSourcesLabel={t('No storages in this category')}
87	              isEditable={false}
88	              testId="storage-mappings-list"
89	            />
90	          </DescriptionListDescription>
91	        </DescriptionListGroup>
92	      </DescriptionList>
93	    </>
94	  );
95	};
96	
97	export default PlanMappingsViewMode;

